function gradeClass(g) {
  if (!g) return 'grade';
  var u = g.toUpperCase();
  if (u === 'A') return 'grade grade-a';
  if (u === 'B') return 'grade grade-b';
  if (u === 'C') return 'grade grade-c';
  return 'grade';
}
window.removePart = function (harvestedPartId) {
  if (!confirm('Remove this part and return it to stock?')) return;
  appsmith.updateModel({
    selectedHarvestedPartId: harvestedPartId
  });
  appsmith.triggerEvent('onRemovePart');
};
window.saveCost = function (harvestedPartId) {
  var input = document.getElementById('cost-input-' + harvestedPartId);
  if (!input) return;
  var val = parseFloat(input.value);
  if (isNaN(val) || val < 0) {
    alert('Enter a valid cost of £0.00 or more.');
    return;
  }
  appsmith.updateModel({
    costUpdatePartId: harvestedPartId,
    costUpdateValue: val
  });
  appsmith.triggerEvent('onSaveCost');
};
function render(model) {
  var allParts = model.installedParts || [];
  var stripped = allParts.filter(function (p) {
    return p.installed_in_asset_id !== null;
  });
  var fitted = (model.fittedParts || []).map(function (f) {
    return {
      part_ref: f.part_ref,
      part_type: f.part_type,
      spec: f.part_make || null,
      condition_grade: null,
      part_cost: f.part_cost,
      harvested_part_id: null
    };
  });
  var parts = stripped.concat(fitted);
  var tbody = document.getElementById('table_body');
  var count = document.getElementById('count');
  var hint = document.getElementById('cost-hint');
  if (!tbody || !count) return;
  count.textContent = parts.length + ' part' + (parts.length !== 1 ? 's' : '');
  var hasMissingCost = parts.some(function (p) {
    return p.harvested_part_id && (p.part_cost === null || p.part_cost === undefined);
  });
  if (hint) hint.style.display = hasMissingCost ? 'block' : 'none';
  if (!parts.length) {
    tbody.innerHTML = '<tr><td colspan="6" class="empty">No parts installed</td></tr>';
    return;
  }
  var total = 0;
  var hasAny = false;
  var rows = parts.map(function (p) {
    var cost = p.part_cost !== null && p.part_cost !== undefined ? parseFloat(p.part_cost) : null;
    if (cost !== null) {
      total += cost;
      hasAny = true;
    }
    var spec = p.spec && p.spec !== 'null' && p.spec !== '' ? p.spec : '—';
    var grade = p.condition_grade && p.condition_grade !== 'null' ? p.condition_grade.toUpperCase() : 'N';
    var costCell;
    if (cost !== null) {
      costCell = '£' + cost.toFixed(2);
    } else if (p.harvested_part_id) {
      costCell = '<div class="cost-input-row">' + '<input type="number" step="0.01" min="0" class="cost-input" id="cost-input-' + p.harvested_part_id + '" placeholder="0.00" />' + '<button class="cost-save-btn" onclick="window.saveCost(' + p.harvested_part_id + ')">Save</button>' + '</div>';
    } else {
      costCell = '—';
    }
    var actionCell = p.harvested_part_id ? '<button class="remove-btn" onclick="window.removePart(' + p.harvested_part_id + ')">Remove</button>' : '';
    return '<tr>' + '<td><span class="part-ref">' + (p.part_ref || '—') + '</span></td>' + '<td>' + (p.part_type || '—') + '</td>' + '<td style="color:#6b7280">' + spec + '</td>' + '<td><span class="' + gradeClass(grade) + '">' + grade + '</span></td>' + '<td>' + costCell + '</td>' + '<td>' + actionCell + '</td>' + '</tr>';
  }).join('');
  if (hasAny) {
    rows += '<tr><td colspan="5" style="text-align:right;font-size:11px;color:#6b7280;padding-top:10px">Total parts cost</td>' + '<td style="font-weight:500;padding-top:10px">£' + total.toFixed(2) + '</td></tr>';
  }
  tbody.innerHTML = rows;
}
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function (model) {
  render(model);
});

